const body = $input.first().json.body || {};

const status            = body.status || 'unknown';
const tenantId          = body.tenant_id || '';
const messagingChannel  = body.messaging_channel || 'telegram';

if (!tenantId) throw new Error('No tenant_id in OAuth callback body');

return [{
  json: {
    tenant_id:         tenantId,
    messaging_channel: messagingChannel,
    status:            status,
    is_success:        status === 'success'
  }
}];

const authData = $('Check Google Auth Status').first().json;
const trigger = $('When Executed by Another Workflow').first().json;

const authUrl = authData.authorization_url ||
  '[URL]' + encodeURIComponent(trigger.tenant_id);

return [{
  json: {
    output: '🔐 To use Gmail and Google Calendar, you need to connect your Google account first.\n\n' +
            'Tap the link below to authorize — it only takes a minute:\n' + authUrl +
            '\n\n✅ Once connected, I\'ll automatically complete what you asked.',
    needs_auth: true,
    tenant_id: trigger.tenant_id,
    messaging_channel: trigger.messaging_channel || 'telegram'
  }
}];

const agentOutput = $('Google Workspace Agent').first().json.output || '';
const trigger = $('When Executed by Another Workflow').first().json;

return [{
  json: {
    output: agentOutput,
    tenant_id: trigger.tenant_id,
    messaging_channel: trigger.messaging_channel || 'telegram',
    needs_auth: false
  }
}];
